import heapq
from dataclasses import dataclass, field
from typing import Dict

@dataclass
class Server:
    host: str
    connections: int = 0
    weight: int = 1

    def __lt__(self, other):
        return (self.connections / self.weight) < (other.connections / other.weight)

class LeastConnectionsBalancer:
    def __init__(self):
        self.servers: Dict[str, Server] = {}

    def add_server(self, host: str, weight: int = 1):
        self.servers[host] = Server(host=host, weight=weight)

    def route(self) -> str:
        # Pick server with least connections per weight
        best = min(self.servers.values(), key=lambda s: s.connections / s.weight)
        best.connections += 1
        return best.host

    def release(self, host: str):
        if host in self.servers:
            self.servers[host].connections = max(0, self.servers[host].connections - 1)

balancer = LeastConnectionsBalancer()
balancer.add_server("server-a", weight=2)
balancer.add_server("server-b", weight=1)
balancer.add_server("server-c", weight=1)

