class MonolithOrderService:
    def __init__(self):
        self.inventory = {"SKU-001": 100, "SKU-002": 50}
        self.orders = []

    def place_order(self, user_id: str, sku: str, qty: int) -> dict:
        # Inventory check
        if self.inventory.get(sku, 0) < qty:
            return {"error": "Out of stock"}
        # Payment (simulated)
        payment = self._charge_payment(user_id, qty * 29.99)
        # Update inventory
        self.inventory[sku] -= qty
        # Create order
        order = {"id": len(self.orders) + 1, "user": user_id, "sku": sku, "qty": qty}
        self.orders.append(order)
        return {"order": order, "payment": payment}

    def _charge_payment(self, user_id: str, amount: float) -> dict:
        return {"status": "charged", "amount": amount}

