import json

class InventoryService:
    def __init__(self):
        self.stock = {"SKU-001": 100, "SKU-002": 50}

    def check_and_reserve(self, sku: str, qty: int) -> dict:
        if self.stock.get(sku, 0) >= qty:
            self.stock[sku] -= qty
            return {"reserved": True, "remaining": self.stock[sku]}
        return {"reserved": False, "reason": "Insufficient stock"}

class PaymentService:
    def charge(self, user_id: str, amount: float) -> dict:
        return {"status": "charged", "amount": amount, "tx_id": "TX-001"}

class OrderOrchestrator:
    """Coordinates between microservices (saga pattern)."""
    def __init__(self, inventory: InventoryService, payment: PaymentService):
        self.inventory = inventory
        self.payment = payment

    def place_order(self, user_id: str, sku: str, qty: int) -> dict:
        # Step 1: Reserve inventory
        inv_result = self.inventory.check_and_reserve(sku, qty)
        if not inv_result["reserved"]:
            return {"error": inv_result["reason"]}
        # Step 2: Charge payment
        pay_result = self.payment.charge(user_id, qty * 29.99)
        return {"order": {"user": user_id, "sku": sku, "qty": qty}, "payment": pay_result}

# Both produce the same result
mono = MonolithOrderService()
print("Monolith:", mono.place_order("user-1", "SKU-001", 2))

inv = InventoryService()
pay = PaymentService()
orch = OrderOrchestrator(inv, pay)
print("Microservice:", orch.place_order("user-2", "SKU-001", 3))
