# Challenge Solution: Design a Rate Limiter
import time
from collections import defaultdict
from dataclasses import dataclass

@dataclass
class RateLimitResult:
    allowed: bool
    remaining: int
    retry_after: float  # seconds until next allowed request

class SlidingWindowRateLimiter:
    """Token bucket rate limiter using sliding window."""
    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.requests = defaultdict(list)  # client_id -> [timestamps]

    def is_allowed(self, client_id: str) -> RateLimitResult:
        now = time.time()
        window_start = now - self.window_seconds

        # Clean old requests
        self.requests[client_id] = [
            t for t in self.requests[client_id] if t > window_start
        ]

        if len(self.requests[client_id]) < self.max_requests:
            self.requests[client_id].append(now)
            remaining = self.max_requests - len(self.requests[client_id])
            return RateLimitResult(True, remaining, 0)
        else:
            oldest = self.requests[client_id][0]
            retry_after = oldest + self.window_seconds - now
            return RateLimitResult(False, 0, retry_after)

# Distributed rate limiter with Redis (conceptual)
class DistributedRateLimiter:
    """Rate limiter using sliding window counter in Redis."""
    def __init__(self, redis_client, max_requests: int, window_seconds: int):
        self.redis = redis_client
        self.max_requests = max_requests
        self.window_seconds = window_seconds

    def is_allowed(self, client_id: str) -> RateLimitResult:
        key = f"ratelimit:{client_id}"
        now = time.time()
        window_start = now - self.window_seconds

        pipe = self.redis.pipeline()
        pipe.zremrangebyscore(key, 0, window_start)  # remove old
        pipe.zadd(key, {str(now): now})               # add current
        pipe.zcard(key)                                # count in window
        pipe.expire(key, self.window_seconds)          # auto-cleanup
        _, _, count, _ = pipe.execute()

        if count <= self.max_requests:
            return RateLimitResult(True, self.max_requests - count, 0)
        else:
            retry_after = self.window_seconds
            return RateLimitResult(False, 0, retry_after)

# Demo
limiter = SlidingWindowRateLimiter(max_requests=5, window_seconds=60)
for i in range(7):
    result = limiter.is_allowed("client-1")
    print(f"Request {i+1}: allowed={result.allowed}, remaining={result.remaining}")
